"""
MKT Christ — Luke chapters 14–16 (97 missing verses; 15:20 already present)
Output: data/commentary/mkt-christ/luke.json
Run: python3 scripts/zc-christ-luke-14-16.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH14_16 = {
"14": {
"1": "<p>Jesus going 'to dine at the house of a ruler of the Pharisees' on the Sabbath situates the healing and teaching that follow within an elite Pharisaic household. Table fellowship with the powerful is itself a Christological act: Christ does not refuse the invitation of those who are 'watching him carefully' (paratereo — the same verb used for hostile surveillance in 6:7; 20:20). His willingness to enter hostile spaces, eat at hostile tables, and teach uncomfortable truths is the pattern of his mission — he goes where he is observed in order to be revealed.</p>",
"2": "<p>The man with dropsy (hydrops — fluid retention) appearing 'before him' may be a deliberate test by the Pharisees, presenting a sympathy-provoking but Sabbath-problematic case. In any case, his presence before Jesus is the occasion for another Sabbath healing that reveals who Jesus is. The man's ailment (swollen from retained fluids) is the opposite of the blessing of the kingdom: where Christ comes, life flows freely, abundance replaces retention, healing replaces withholding. The dropsy-healer is himself the living water who quenches every thirst (John 4:14; 7:37-38).</p>",
"3": "<p>'Is it lawful to heal on the Sabbath, or not?' — Jesus addresses the legal question before healing, exposing the watching lawyers' and Pharisees' heart-position. The silence of the lawyers and Pharisees reveals their internal conflict: they cannot affirm the healing (it would validate Jesus) or deny its permissibility (it would appear heartless). Their silence before Christ's question is the silence of bad faith — they know the answer but will not speak it. Christ acts from love; they calculate from self-protection. His question reveals the difference.</p>",
"4": "<p>'He took him and healed him and sent him away' — the threefold action (took, healed, sent) is characteristically Lukan: Jesus acts with decisiveness, completeness, and releasing generosity. He does not keep those he heals as demonstrations of his power; he heals them and sends them to their own lives. The healing on the Sabbath is the enacted answer to the legal question: the one who is Lord of the Sabbath (6:5) fulfills the Sabbath's purpose — rest, restoration, liberation — by healing the man who cannot rest in his waterlogged body.</p>",
"5": "<p>'Which of you, having a son or an ox that has fallen into a well on a Sabbath day, will not immediately pull him out?' — the argument from emergency: if even Sabbath-restrictions yield to rescue a son or ox from a well, how much more should Sabbath-restrictions yield before the healing of a human being who has been in his 'well' of illness for years. The a fortiori logic (from the lesser to the greater) is Christ's consistent Sabbath-healing argument (13:15-16). He is not breaking the Sabbath but fulfilling its deepest purpose: liberation from every bondage.</p>",
"6": "<p>'And they could not reply to these things' — the silence of the lawyers and Pharisees in the face of Christ's Sabbath-rescue argument is not the silence of assent but the silence of defeat without capitulation. They cannot answer because the argument is unanswerable within their own legal framework; they will not agree because agreeing would require accepting Jesus's authority. Their silence is the silence of hardened hearts before the truth — a silence that will deepen into active conspiracy rather than repentance.</p>",
"7": "<p>The parable of the wedding seats is addressed to guests Jesus observed choosing places of honor (tous prōtoklisias — the couches nearest the host, the highest honor in ancient Mediterranean dining). The observation becomes a parable about the kingdom's honor-logic. Christ, the one who sat in the highest place (Phil 2:6 — 'in the form of God... equal with God') took the lowest place (Phil 2:7-8 — 'emptied himself... humbled himself to death on a cross'). His parable is his own biography: the humble exalted, the proud brought low.</p>",
"8": "<p>'When you are invited by someone to a wedding feast, do not sit down in a place of honor, lest someone more distinguished than you be invited by him' — the wisdom of the kingdom is the wisdom of self-lowering. The Proverbs-wisdom background (Prov 25:6-7 — 'do not put yourself forward in the king's presence or stand in the place of the great') anticipates what Christ embodies: he who is the King of kings comes not to the highest place but to the manger, the carpenter's shop, the cross. Kingdom wisdom is incarnation-shaped.</p>",
"9": "<p>'And he who invited you both will come and say to you, Give your place to this person, and then you will begin with shame to take the lowest place' — the public shame of being displaced from a self-claimed seat captures the eschatological dimension of self-exaltation. In the kingdom's final accounting, every self-promoted position is vacated; every self-inflated claim is punctured. The one who pushed to the front will be directed to the back. Christ's passion is the supreme example of this: the one who was truly greatest was pushed to the back — crucified outside the city gates.</p>",
"10": "<p>'But when you are invited, go and sit in the lowest place, so that when your host comes he may say to you, Friend, move up higher' — the humility-exaltation reversal is not a social strategy for getting higher seats but a description of the kingdom's operating principle. Christ takes the lowest place (incarnation, death, burial) so that the Father says 'Friend, move up higher' (resurrection, ascension, enthronement at the right hand). The host's invitation to move up is the resurrection vindication of the one who died in apparent defeat.</p>",
"11": "<p>'For everyone who exalts himself will be humbled, and everyone who humbles himself will be exalted' — this aphorism (also 18:14) is the law of the kingdom derived from Christ's own life-pattern. His descent from the Father's presence through incarnation and crucifixion is the ultimate self-humbling; his resurrection-ascension-enthronement is the ultimate exaltation. Every disciple's cross-bearing participates in this pattern: 'if we have died with him, we will also live with him; if we endure, we will also reign with him' (2 Tim 2:11-12).</p>",
"12": "<p>'When you give a dinner or a banquet, do not invite your friends or your brothers or your relatives or rich neighbors, lest they also invite you in return and you be repaid' — the reciprocity of conventional hospitality (invite those who will invite you back) is the social logic that Christ transcends in his own table-fellowship. He eats with those who cannot repay: tax collectors, sinners, the sick, the marginal. His table-fellowship is not calculated reciprocity but gratuitous grace — the form of the kingdom's invitation which he himself embodies and now teaches.</p>",
"13": "<p>'But when you give a feast, invite the poor, the crippled, the lame, the blind' — the four categories (poor, crippled, lame, blind) are the same groups who appear in the next parable as those invited to the great banquet (v.21) and in the Jubilee proclamation of 4:18 (poor, captive, blind, oppressed). Christ himself declares his own invitation to these groups (7:22 — 'the blind receive their sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, the poor have good news preached to them'). The teaching reflects his own practice.</p>",
"14": "<p>'And you will be blessed, because they cannot repay you. For you will be repaid at the resurrection of the just' — the eschatological repayment (at the resurrection) makes kingdom hospitality a form of investment in the age to come rather than social capital in this age. Christ's own death is the supreme example: he gave everything for those who could not repay him; his repayment is the resurrection and the gathering of those he redeemed. 'The resurrection of the just' is the moment when every act of unrequited kingdom-love receives its divine recompense.</p>",
"15": "<p>'When one of those who reclined at table with him heard these things, he said to him, Blessed is everyone who will eat bread in the kingdom of God!' — the anonymous table-companion's exclamation about the eschatological banquet triggers the parable of the Great Banquet. His beatitude is correct but complacent: he assumes his own place at the kingdom table. The parable will challenge this assumption. Christ himself is the host of the great banquet (Rev 19:7-9 — the wedding supper of the Lamb) whose invitations are being sent now and whose table includes many the invited guests refused to attend.</p>",
"16": "<p>'A man once gave a great banquet and invited many' — the great banquet of the kingdom (Isa 25:6 — 'a feast of rich food for all peoples, a feast of well-aged wine, of rich food full of marrow, of aged wine well refined') is prepared by the host who is Christ himself. His incarnation is the preparation of the banquet; his cross is the slaughter of the fatted animals; his resurrection and mission are the sending of the servants. The 'many' who are invited are Israel first — the covenant people first invited to the messianic feast.</p>",
"17": "<p>'And at the time for the banquet he sent his servant to say to those who had been invited, Come, for everything is now ready' — the servant's announcement 'everything is now ready' is the gospel proclamation: the cross has accomplished what is needed; the invitation stands. Christ sends his servants (the apostles) to those already invited (Israel) saying 'come now.' The 'now' of the ready banquet is the eschatological now of the new covenant: the time for preparation is past; the feast is ready; the invitation is urgent.</p>",
"18": "<p>'But they all alike began to make excuses' — the unanimous refusal of the original invitees (who had accepted the invitation in advance) is the parable's indictment of Israel's rejection of Christ. The three excuses (land, oxen, wife) represent legitimate activities that have been elevated above the urgent invitation. None of the excuses is sinful in itself; all of them are disqualifying when they replace the kingdom's invitation. The tragedy is not wickedness but priority-inversion: good things treated as ultimate things crowd out the truly ultimate.</p>",
"19": "<p>'I have bought five yoke of oxen, and I go to examine them' — the agricultural investment excuse represents the distraction of legitimate business from the kingdom's invitation. The oxen-purchaser is not evil; he is reasonable by worldly standards. But the kingdom's invitation is not a reasonable option to balance against other reasonable options: it is the summons of the Lord himself to the eschatological feast. The reasonable man who misses the feast for a reasonable reason misses it just as completely as the unreasonable man who refuses with contempt.</p>",
"20": "<p>'I have married a wife, and therefore I cannot come' — the marital excuse is the most poignant: the institution God established (marriage, Gen 2:24) becomes the reason for refusing God's invitation. There is a discipleship-cost here: even the most intimate and legitimate human bonds must not override the kingdom's call. Jesus himself said that love for him must outweigh even family love (14:26 — hating father, mother, wife in comparison). The married man's excuse represents the good things of this life that can functionally replace God as the ultimate priority.</p>",
"21": "<p>'Go out quickly to the streets and lanes of the city, and bring in the poor and crippled and blind and lame' — the Jubilee-groups (again: poor, crippled, blind, lame — from 4:18; 14:13) are invited when the originally-invited refuse. This is the pattern of Christ's own ministry: when the religious establishment rejected him, his table opened to sinners, tax collectors, the marginal, the unclean. The banquet is filled — but with those the Pharisee-table-companion (v.15) would have considered unworthy. The host's generosity overflows every social boundary.</p>",
"22": "<p>'And the servant said, Sir, what you commanded has been done, and still there is room' — the abundance of the banquet (there is still room after all the poor and marginalized have been invited) is the eschatological superabundance of the kingdom. Grace is not a limited resource that runs out when the 'deserving' have received it; it overflows every vessel. The 'still there is room' is the gospel's inexhaustible invitation: Christ's table has never been full, the welcoming arms of the father (15:20) are never withdrawn, the door is open until the hour of closing (13:25).</p>",
"23": "<p>'Go out to the highways and hedges and compel people to come in, that my house may be filled' — the second expansion of the invitation (from city-poor to country-outsiders) represents the Gentile mission. The compulsion (anankason — compel) is not coercion but urgent persuasion: the host's insistence that his table be full drives the servants to seek those who would never self-invite. Augustine famously used this verse to justify state-compelled religion — a gross misapplication. The compulsion is the persuasion of the gospel: 'we implore you on behalf of Christ, be reconciled to God' (2 Cor 5:20).</p>",
"24": "<p>'For I tell you, none of those men who were invited shall taste my banquet' — the solemn exclusion of the original-invitees-who-refused is the judgment word at the parable's end. They will not taste what they declined. The great banquet is not perpetually open: there is a moment of closure (the banquet begins, the door shuts, 13:25). Those who persistently refuse the invitation — whether through explicit rejection or through good-excuse priority-inversion — are excluded by their own choices. The tragedy is that the feast was prepared for them; they simply would not come.</p>",
"25": "<p>'Now great crowds accompanied him' — the large crowd following Jesus on the road to Jerusalem sets the scene for the hardest discipleship-cost teachings. The popularity of Jesus's following does not soften his demands; it sharpens them. He turns to address the crowds (v.25 — 'he turned and said to them') with the most demanding words he will speak about discipleship. The crowd's enthusiasm is precisely the moment Christ calls for honest cost-counting: following him to the cross requires more than crowd-momentum.</p>",
"26": "<p>'If anyone comes to me and does not hate his own father and mother and wife and children and brothers and sisters, yes, and even his own life, he cannot be my disciple' — 'hate' (miseo) here is the Semitic comparative idiom for 'love less than': love for Christ must relativize every other love. This is the demand of the First Commandment (no other gods before me) applied to discipleship. Christ himself models this: he left the Father's presence (John 17:5 — the glory he had before the world) for the Incarnation; he submitted his natural desire to live to the Father's will at Gethsemane (22:42). Absolute love for God relativizes all other loves.</p>",
"27": "<p>'Whoever does not bear his own cross and come after me cannot be my disciple' — the cross-bearing saying (also 9:23 with 'daily') places the instrument of Christ's death as the identifying mark of his followers. Before the cross was the supreme sacrifice-altar, it was a Roman execution-device — humiliation, public shaming, slow death. The disciples are called into the posture of the condemned: accepting social death, embracing shame for Christ's sake, following him to the place of execution. The one who bore the cross first (23:26) calls all who follow him to take up their own.</p>",
"28": "<p>'For which of you, desiring to build a tower, does not first sit down and count the cost?' — the tower-builder parable applies practical wisdom to discipleship. The wisdom of honest cost-assessment before undertaking a project is universally recognized; Christ applies it to the decision to follow him. The 'cost' of discipleship is the entire self (v.26 — his own life, v.27 — his own cross). Those who begin without counting the cost will abandon the project when the price becomes clear. Honest disciples are those who have reckoned with the full cost before beginning.</p>",
"29": "<p>'Otherwise, when he has laid a foundation and is not able to finish, all who see it begin to mock him' — the public mockery of the half-completed tower is the eschatological failure of half-hearted discipleship. Those who begin the way of the cross and then abandon it are exposed before the watching world — and before the eschatological judgment — as having miscalculated. The shame of abandonment is greater than the shame of never starting. Christ's own completion of the cross (John 19:30 — 'It is finished') is the model of the fully-counted, fully-paid, fully-completed cost.</p>",
"30": "<p>'This man began to build and was not able to finish' — the mocking of the failed builder is the counterpoint to the completed tower. The failed builder represents the disciple who began with enthusiasm but without genuine cost-counting — the shallow soil (8:13 — 'in time of testing fall away'). Christ's call to discipleship is not a call to begin with enthusiasm; it is a call to continue to the end. The one who endures to the end will be saved (Matt 10:22); the one who falls away in the middle has demonstrated that the foundation was insufficient.</p>",
"31": "<p>'Or what king, going to encounter another king in war, will not sit down first and deliberate whether he is able with ten thousand to meet him who comes against him with twenty thousand?' — the military cost-counting parable applies the same principle to the assessment of one's own resources against the enemy's. The disciple must honestly reckon: am I strong enough to follow Christ all the way to the cross? The honest answer is: no, not in my own strength. The parable implicitly points to the necessity of Christ's resources supplementing the disciple's own — discipleship is not self-reliance but union with the one who has already defeated every enemy.</p>",
"32": "<p>'And if not, while the other is yet a great way off, he sends a delegation and asks for terms of peace' — the king who cannot match the opposing force seeks terms of peace before the battle. Applied to discipleship: the one who honestly reckons his inability to follow Christ must seek terms of peace with the one demanding unconditional surrender. Christ is the opposing king who comes with overwhelmingly superior force — the only rational response is surrender, which is discipleship. The 'terms of peace' are the terms of the kingdom: lose your life, take up the cross, follow me.</p>",
"33": "<p>'So therefore, any one of you who does not renounce all that he has cannot be my disciple' — the conclusion of both cost-counting parables: discipleship requires the renunciation of all possessions (apotassetai pasin tois heautou hyparchousin). This is the radical version of the kingdom's economics: everything the disciple holds must be held loosely, as a steward not an owner. Christ himself renounced all: 'though he was rich, yet for your sake he became poor, so that you by his poverty might become rich' (2 Cor 8:9). His total renunciation enables and models total discipleship.</p>",
"34": "<p>'Salt is good, but if salt has lost its taste, how shall its saltiness be restored?' — the salt metaphor for discipleship follows the renunciation-teaching: disciples who have abandoned the cross-shaped life are like salt that has lost its saltiness — outwardly similar but without the essential quality that makes them useful. The Sermon on the Mount calls disciples 'the salt of the earth' (Matt 5:13). Christ is himself the salt — the preserving, flavoring, purifying presence that disciples carry. Without the cross-shaped life, discipleship is the form without the substance.</p>",
"35": "<p>'It is of no use either for the soil or for the manure pile. It is thrown away. He who has ears to hear, let him hear' — the uselessness of saltless salt (it cannot even fertilize!) is the uselessness of cross-less discipleship. The summons to 'hear' (akouetō — the same prophetic summons as 8:8 and 14:35) closes the discipleship-cost section. The ears needed to hear this teaching are the ears opened by the Spirit (Acts 2:37 — 'cut to the heart'). Without the Spirit's illumination, these demands appear harsh; with it, they appear liberating — the path of the cross is the path of resurrection.</p>"
},
"15": {
"1": "<p>'Now the tax collectors and sinners were all drawing near to hear him' — the gathering of tax collectors and sinners around Jesus is the enacted answer to the question the chapter's three parables will address: why does Christ eat with sinners? Their drawing near (ēggizon — they were coming close) is the movement toward Christ that every sinner must make. They come to hear — and hearing, they find the seeking-finding-feasting Father. Christ's attraction for the socially excluded is not despite his holiness but because of it: the Holy One of God is also the Savior of sinners (1 Tim 1:15).</p>",
"2": "<p>'And the Pharisees and the scribes grumbled, saying, This man receives sinners and eats with them' — the Pharisaic grumbling (diagongyzō — the LXX word for Israel's wilderness murmuring, 5:30; 19:7) is the occasion for the three parables. Their complaint is accurate: Jesus does receive sinners and eat with them. Their error is in treating this as a scandal. Christ's eating with sinners is not a compromise of his holiness but the expression of the Father's character: the God who pursues the lost, rejoices at their return, and throws a party for the found. The Pharisees grumble; the Father celebrates.</p>",
"3": "<p>The three parables of Luke 15 (lost sheep, lost coin, lost son) form the Gospel's most sustained account of the Father's heart toward the lost. They are Christ's theological self-defense: this is why I eat with sinners — because this is what the Father is like, and I am doing what the Father does. The parables are not merely ethical teachings about generosity; they are Christological declarations about the divine mission of seeking and saving. Christ is the seeking Shepherd (vv.4-7), and his entire Incarnation is the going-after of the one lost sheep.</p>",
"4": "<p>'What man of you, having a hundred sheep, if he has lost one of them, does not leave the ninety-nine in the open country, and go after the one that is lost, until he finds it?' — the Good Shepherd who leaves the ninety-nine for the one is Christ himself (John 10:11-16 — 'I am the good shepherd... I lay down my life for the sheep'). The one lost sheep is the entire human race — lost from God through the Fall. The Incarnation is the shepherd's leaving the fold (heaven) to go into the open country (fallen creation) to seek the lost. The cross is the rescue; the resurrection is the finding.</p>",
"5": "<p>'And when he has found it, he lays it on his shoulders, rejoicing' — the shepherd who lays the found sheep on his shoulders is the image of Christ carrying the cross (Luke 23:26; John 19:17) and also of the image of Christ bearing his people (Isa 46:4 — 'I will carry you'). The rejoicing (chairōn) of the shepherd is the 'joy set before him' (Heb 12:2) for which Christ endured the cross — the eschatological joy of recovering the lost. The shepherd's shoulders are the cross; the sheep laid across those shoulders is the redeemed humanity; the rejoicing is the resurrection-joy of completed redemption.</p>",
"6": "<p>'And when he comes home, he calls together his friends and his neighbors, saying to them, Rejoice with me, for I have found my sheep that was lost' — the communal celebration over the found sheep previews the resurrection-joy that Christ's recovery of lost humanity produces in heaven. 'Rejoice with me' is the invitation to share in the Shepherd's own joy — the joy of the triune God over the salvation of sinners. This is the eschatological party that the Father throws (v.22-24 in the prodigal son), the wedding supper of the Lamb (Rev 19:7-9), the final gathering that every saving event anticipates.</p>",
"7": "<p>'Just so, I tell you, there will be more joy in heaven over one sinner who repents than over ninety-nine righteous persons who need no repentance' — the disproportionate joy over the one repentant sinner is the measure of how much God values the recovery of the lost. The 'ninety-nine righteous who need no repentance' is not a real category (all have sinned, Rom 3:23) but the self-righteous category that the grumbling Pharisees occupy in their own minds. The joy of heaven — shared by Father, Son, Spirit, and angels (v.10) — is the measure of the value of one saved soul.</p>",
"8": "<p>'Or what woman, having ten silver coins, if she loses one coin, does not light a lamp and sweep the house and seek diligently until she finds it?' — the second parable of seeking uses a woman seeking a lost coin as the image of divine diligence in recovering what is lost. The lamp she lights is the light of the gospel (John 1:9 — Christ as the true light; Luke 11:33-36 — the lamp that illuminates the whole house). The thorough searching (katarousan — sweeping carefully) is the thoroughness of the divine search for the lost — the Incarnation leaving no corner of human experience unexplored.</p>",
"9": "<p>'And when she has found it, she calls together her friends and neighbors, saying, Rejoice with me, for I have found the coin that I had lost' — the third instance of communal joy-in-recovery prepares for the full communal celebration of the prodigal son's return (vv.22-32). The pattern is consistent: finding → communal joy. Heaven's joy at a sinner's return (v.10) is not private or quiet; it is the communal celebration of all who love the Seeker. The coin's finding is celebrated by the whole neighborhood; the sinner's finding is celebrated by the whole company of heaven.</p>",
"10": "<p>'Just so, I tell you, there is joy before the angels of God over one sinner who repents' — the angelic joy at human repentance is the joy of those who have been waiting and watching the divine redemption-drama unfold. The angels who announced Christ's birth (2:10-14 — 'great joy'), who ministered to him in Gethsemane (22:43), and who announced his resurrection (24:4-7) are also those who celebrate every sinner's return. The recovery of one lost soul is an event of universal cosmic significance — the continuation of the great redemption-drama that began with the Incarnation.</p>",
"11": "<p>'And he said, There was a man who had two sons' — the third and greatest parable of Luke 15 introduces the prodigal son. The two sons represent two ways of being lost: the younger (far from home, conscious of sin) and the elder (near home, unconscious of his own lostness). Christ comes for both — and the parable ends with the Father's arms open to both. The two sons together represent the totality of human alienation from God: explicit rebellion (younger) and religious self-righteousness (elder), both needing the Father's welcome.</p>",
"12": "<p>'Father, give me the share of property that is coming to me' — the younger son's demand for his inheritance while his father is living is an act of social death: symbolically wishing the father dead in order to receive what a dead father would give. This is the image of human sin against the Father: the creation demands from God the benefits of his generosity while treating him as dead — pushing him aside as irrelevant while using his gifts. The Incarnation is the Father's response: not punitive withdrawal but self-giving love (John 3:16 — 'he gave his only Son').</p>",
"13": "<p>'Not many days later, the younger son gathered all he had and took a journey into a far country, and there he squandered his property in reckless living' — the far country (chōran makran) is the alienation of sin from the Father. The 'recklessness' (asōtōs — prodigally, without saving) is the misuse of the good gifts the Father gave. The created order is the Father's gift to humanity (Gen 1-2); the misuse and exploitation of creation is the prodigal living in the far country. Christ comes from the Father's presence into this far country (Phil 2:7 — 'coming in human likeness') to bring the prodigal home.</p>",
"14": "<p>'And when he had spent everything, a severe famine arose in that country, and he began to be in need' — the famine that empties the far country and brings the son to destitution is the natural consequence of the life without the Father. Apart from the Father, every resource is finite; every pleasure fades; every abundance runs out. The son who demanded everything from the father has nothing when the father's gifts are exhausted. This is the portrait of fallen humanity without God: finite resources, growing need, no recourse. The gospel begins at the moment of 'he began to be in need.'</p>",
"15": "<p>'So he went and hired himself out to one of the citizens of that country, who sent him into his fields to feed pigs' — the Israelite son feeding pigs (ritually impure animals, Lev 11:7) in a Gentile land is the image of complete degradation: covenant people serving idols, the image of God reduced to pig-keeping. This is the portrait of Israel in exile — and of all humanity in the far country of sin: made for communion with the Father, reduced to feeding swine. The 'citizen of that country' to whom he is enslaved is the image of every power that exploits the human being separated from God.</p>",
"16": "<p>'And he was longing to be fed with the pods that the pigs ate, and no one gave him anything' — the son's longing for pig-food and the giving of 'nothing' by anyone pictures the complete abandonment of the far country. In the Father's house there is 'enough and to spare' (v.17); in the far country, not even pig food satisfies. The hunger of the far country is the hunger that only the Father can fill — the restlessness Augustine described: 'our heart is restless, until it finds its rest in Thee.' The feeding of the five thousand (9:17 — all ate and were satisfied) is Christ's provision for those who have been 'given nothing' by the world.</p>",
"17": "<p>'But when he came to himself, he said, How many of my father's hired servants have more than enough bread, but I perish here with hunger!' — 'coming to himself' (eis heauton elthōn — coming into himself) is the moment of repentance's beginning: the recovery of sanity, the recognition of where one truly is. The prodigal's self-recognition (I am perishing; my father's house has abundance) is the first movement of repentance. This coming-to-oneself is the work of the Spirit (John 16:8 — 'when he comes, he will convict the world concerning sin'). Repentance is not self-generated but Spirit-enabled.</p>",
"18": "<p>'I will arise and go to my father, and I will say to him, Father, I have sinned against heaven and before you' — the prodigal's prepared confession ('sinned against heaven and before you') acknowledges two dimensions of sin: the vertical (against God/heaven) and the horizontal (before the father's face). This is David's double-confession in Ps 51:4 — 'Against you, you only, have I sinned, and done what is evil in your sight.' The prodigal's recognition that his sin is first against God, not merely against himself or social convention, is the beginning of genuine repentance rather than mere regret.</p>",
"19": "<p>'I am no longer worthy to be called your son. Treat me as one of your hired servants' — the prodigal's self-assessment of unworthiness is accurate (he has forfeited his sonship by his actions) but his proposed solution (hired servant) underestimates the Father's grace. He can imagine being taken back as a servant; he cannot imagine being received as a son. The Father's response will exceed every expectation: not hired servant but fully restored son, clothed, ringed, feasted. This is the pattern of grace: the sinner's self-estimation is accurate about sin but radically underestimates the Father's love.</p>",
"20": "<p>Already present.</p>",
"21": "<p>'And the son said to him, Father, I have sinned against heaven and before you. I am no longer worthy to be called your son' — the prodigal's prepared speech is interrupted before completion: the father does not wait to hear the 'treat me as a hired servant' proposal. The interruption is itself the grace — the father's actions (robe, ring, sandals, feast) preempt and exceed the son's request. Christ does not wait for the sinner to finish the penitential speech before the forgiveness is given: on the cross, 'Father, forgive them' (23:34) is spoken before any request comes from the crucifiers.</p>",
"22": "<p>'But the father said to his servants, Bring quickly the best robe, and put it on him, and put a ring on his hand, and shoes on his feet' — the restoration items are the marks of full restored sonship: the best robe (covering the shame of the far-country rags — cf. Christ clothing the naked; Isa 61:10 — 'he has clothed me with garments of salvation'), the ring (signet ring — restored authority), and sandals (slaves went barefoot; sonship restores shoes). The Father's rapid clothing of the returning prodigal is the Incarnation-pattern: Christ covers human shame with his own righteousness (2 Cor 5:21 — 'he made him to be sin... so that in him we might become the righteousness of God').</p>",
"23": "<p>'And bring the fattened calf and kill it, and let us eat and celebrate' — the feast (euophranthōmen — let us be merry/rejoice) for the returning prodigal is the eschatological feast of the kingdom (Isa 25:6; Rev 19:7-9 — the wedding supper of the Lamb). The fattened calf killed for the celebration echoes the Passover sacrifice and foreshadows the cross: the Father's feast for returning sinners is made possible by the death of the Son, who is himself the sacrificial lamb (John 1:29 — 'the Lamb of God who takes away the sin of the world'). The feast flows from the sacrifice.</p>",
"24": "<p>'For this my son was dead, and is alive again; he was lost, and is found' — the double reversal (dead-to-alive, lost-to-found) is the resurrection-pattern stated in explicit terms. The prodigal was spiritually dead (Eph 2:1 — 'dead in trespasses and sins') and has been made alive (Eph 2:5 — 'made us alive together with Christ'). He was lost (9:10 — 'the Son of Man came to seek and to save the lost') and is found. The father's declaration over the returning prodigal is the Father's declaration over every returning sinner — and its grammar is the grammar of resurrection: was dead, is alive; was lost, is found.</p>",
"25": "<p>'Now his elder son was in the field, and as he came and drew near to the house, he heard music and dancing' — the elder son outside the house while the celebration is inside creates the spatial image of the self-righteous who remain outside the feast. He has 'been here all the time' (v.29) — geographically near the father but spiritually distant. The music and dancing he hears from outside is the sound of the kingdom's celebration that he refuses to join. The elder son represents those who are 'almost in' — near the father but without the father's heart.</p>",
"26": "<p>'And he called one of the servants and asked what these things meant' — the elder son's need to ask about what is happening in his own father's house reveals the depth of his alienation. He has been near the father for years without knowing the father's heart. The Pharisees who grumbled (v.2) are in exactly this position: they know the law, they perform its requirements, but they do not know the father who gives the law — they do not know that the father runs, embraces, and feasts. Near in observance, far in heart.</p>",
"27": "<p>'And he said to him, Your brother has come, and your father has killed the fattened calf, because he has received him back safe and sound' — the servant's report describes the father's actions without their internal motivation. The elder son receives only the external facts: the return, the calf-killing, the reception. He does not receive the internal reality: the father's love, the resurrection-joy, the grace. The external facts without the internal motivation produce anger rather than celebration. This is the Pharisees' position: they see Jesus's actions (eating with sinners) without understanding the Father's heart (seeking and saving the lost).</p>",
"28": "<p>'But he was angry and refused to go in. His father came out and entreated him' — the elder son's anger and refusal to enter is the Pharisees' anger at the gospel's inclusiveness. But the father comes out — again (he ran toward the prodigal, v.20; he comes out to the elder son, v.28). The Father pursues both sons. This is the shape of the divine love: it does not wait inside for the lost to come; it goes out after both the far-country rebel and the near-home moralist. The elder son's exclusion from the feast is self-chosen; the father comes out to invite him in.</p>",
"29": "<p>'Look, these many years I have been serving you, and I never disobeyed your command, yet you never gave me a young goat, that I might celebrate with my friends' — the elder son's complaint reveals his fundamental misunderstanding: he has been treating the father's household as an employer-employee relationship rather than a father-son relationship. He counts years, counts commands obeyed, counts goats not given. He has been in the father's house without access to the father's heart — a description of legal religion without the Spirit, of service without sonship (Gal 4:1-7).</p>",
"30": "<p>'But when this son of yours came, who has devoured your property with prostitutes, you killed the fattened calf for him!' — the elder son's 'this son of yours' (not 'my brother') distances himself from both the prodigal and the father. His bitterness is the bitterness of those who have worked without understanding grace — who have kept accounts and find the grace-economy unfair. Christ's answer to this complaint is not explanation but invitation: 'Son, you are always with me, and all that is mine is yours' (v.31). The elder son had everything and did not know it, because he was counting goats instead of enjoying the father.</p>",
"31": "<p>'Son, you are always with me, and all that is mine is yours' — the father's gentle address ('Son' — teknon, child) and the declaration of the elder son's permanent access to all the father has is the corrective to his servant-mentality. The elder son has been treating as an employee what he has as a son. This is the believer's position: 'if children, then heirs — heirs of God and fellow heirs with Christ' (Rom 8:17). The elder son already has everything the Father has — but joy in it requires receiving the Father's heart, not merely occupying the Father's house.</p>",
"32": "<p>'It was fitting to celebrate and be glad, for this your brother was dead, and is alive; he was lost, and is found' — the parable ends with the father's invitation standing and the elder son's response unresolved. The dead-alive, lost-found reversal is restated for the elder son: it is fitting (edei — divine necessity) to rejoice, because this is what the resurrection looks like. The parable ends open: will the elder son enter the feast? Luke leaves the question open for the Pharisees — will they accept the justification of sinners and enter the kingdom's joy? The invitation stands.</p>"
},
"16": {
"1": "<p>The parable of the dishonest manager (oikonomos — steward) is addressed 'to the disciples' (v.1) rather than the Pharisees, making it an inner-circle teaching about kingdom economics. The manager who is 'wasting the master's possessions' (diaskorpizōn ta hyparchonta autou) uses the same verb as the prodigal who 'squandered his property' (15:13 — dieskorpisen). The connection is deliberate: the dishonest manager and the prodigal both misuse entrusted resources — but the dishonest manager responds to his crisis more shrewdly than many do to the kingdom's crisis.</p>",
"2": "<p>'What is this that I hear about you? Turn in the account of your management, for you can no longer be manager' — the manager's accountability before the master is the eschatological accounting that awaits every steward. Christ is the Master who will call all stewards to account: 'each of us will give an account of himself to God' (Rom 14:12). The dismissal-notice creates urgency — the same urgency the gospel creates: the time of stewardship is not indefinite. The crisis of being called to account is the moment that reveals true priorities.</p>",
"3": "<p>'What shall I do, since my master is taking the management away from me? I am not strong enough to dig, and I am ashamed to beg' — the manager's self-assessment (not strong enough, too ashamed) is honest about his limitations in a way that leads to creative action. His cunning is not the virtue commended but its application — using the present moment of crisis to secure the future. Christ calls disciples to the same crisis-awareness: the present moment is the moment of decision; the future is shaped by present action. The manager's cunning is redirected in v.9 toward kingdom investment.</p>",
"4": "<p>'I have decided what to do, so that when I am removed from management, people may receive me into their houses' — the manager's strategy (using present resources to secure future welcome) is the principle Christ commends: use 'unrighteous mammon' (v.9) to make friends who will receive you into the 'eternal tents' (eternal dwellings). The kingdom application: wealth is unrighteous (it cannot secure eternity), but it can be used to secure kingdom-relationships that will endure. Generosity now creates a welcome later — the economics of the kingdom inverted from the world's economy.</p>",
"5": "<p>'So, summoning his master's debtors one by one, he said to the first, How much do you owe my master? He said, A hundred measures of oil' — the manager's reduction of debts on the master's accounts is the commended shrewdness. The application point (v.9) is not that dishonesty is commended but that urgent, creative, future-securing action with present resources is. Christ himself reduces the debt of sinners — 'your sins are forgiven you' (7:48) — not through dishonesty but through his own payment of the debt on the cross. He who paid what was owed secures for sinners eternal welcome.</p>",
"6": "<p>'He said, Take your bill, and sit down quickly and write fifty' — the rapid reduction (from 100 to 50 measures of oil) creates immediate obligation and gratitude in the debtors. The manager's swift action in the time of crisis secures his future. The application to discipleship is the urgency of present action for eternal investment. The 'quickly' (tacheōs) of the manager's instruction is the urgency of the gospel: now is the acceptable time, now is the day of salvation (2 Cor 6:2). Delayed response to the kingdom's crisis is the failure the parable warns against.</p>",
"7": "<p>'Then he said to another, And how much do you owe? He said, A hundred measures of wheat. He said to him, Take your bill and write eighty' — the second debt-reduction continues the manager's systematic strategy. The wheat-oil symbolism may be significant: wheat and oil are the basic sustenance goods of Palestinian agriculture — the master's wealth is in the basics of life that feed people. The reduction of food-debts creates bonds of practical obligation. Christ's kingdom economics similarly reduces the heaviest burdens and creates bonds of gratitude-obligation (6:38 — 'the measure you give will be the measure you get back').</p>",
"8": "<p>'The master commended the dishonest manager for his shrewdness. For the sons of this age are more shrewd in dealing with their own generation than the sons of light' — the master's commendation is specifically for shrewdness (phronimōs — practically wise) not for dishonesty. Christ applies this: 'the sons of this age' (worldly people) apply more practical wisdom to their temporal affairs than 'the sons of light' (disciples) apply to eternal affairs. The diagnosis is pointed: Christians often treat eternal investment with less urgency and creativity than businesspeople treat financial investment. The parable calls for parity of urgency.</p>",
"9": "<p>'And I tell you, make friends for yourselves by means of unrighteous wealth, so that when it fails they may receive you into the eternal dwellings' — the kingdom application: use money (unrighteous mammon — mamōnas adikias) generously to make kingdom-friends (through charity, hospitality, generosity) who will be waiting in the eternal dwellings when money fails (at death). The 'eternal tents' (aiōnious skēnas) echoes the Feast of Tabernacles imagery and foreshadows the new creation's dwelling-places (John 14:2 — 'many rooms in my Father's house'). Generosity is not merely a virtue but an eternal investment strategy.</p>",
"10": "<p>'One who is faithful in a very little is also faithful in much, and one who is dishonest in a very little is also dishonest in much' — the faithfulness-principle makes wealth-stewardship a training-ground for kingdom stewardship. The 'very little' of earthly wealth trains the character that will be trusted with 'much' in the kingdom (19:17 — 'because you have been faithful in a very little, you shall have authority over ten cities'). Christ himself was 'faithful over God's house as a son' (Heb 3:6) — the model of the one entrusted with everything because he was faithful in everything.</p>",
"11": "<p>'If then you have not been faithful in the unrighteous wealth, who will entrust to you the true riches?' — the 'true riches' (alethinon) in contrast to 'unrighteous wealth' (mamōnas adikias) is the kingdom's genuine treasure: eternal life, relationship with God, the inheritance of the new creation. Faithfulness with money is the prerequisite for being trusted with true riches — not because wealth is important but because how we handle the relatively unimportant reveals the character that will handle the truly important. The eschatological judgment includes an accounting of earthly stewardship.</p>",
"12": "<p>'And if you have not been faithful in that which is another's, who will give you that which is your own?' — the earthly wealth that disciples manage is 'another's' (allotriō — someone else's, namely God's). Everything belongs to God; disciples are stewards, not owners. Faithfulness in stewarding God's resources (treating them as the owner's, not as one's own) qualifies for receiving what is 'your own' — the inheritance that Christ secures for believers (Eph 1:13-14 — the Spirit as the guarantee of our inheritance). The faithful steward becomes the heir.</p>",
"13": "<p>'No servant can serve two masters, for either he will hate the one and love the other, or he will be devoted to the one and despise the other. You cannot serve God and money' — the impossibility of serving both God and mammon is not merely a practical difficulty but a structural impossibility: lordship is exclusive. Christ is Lord (Kyrios — the same word as God/YHWH throughout the LXX); mammon cannot share the lordship-role. The Shema (Deut 6:4 — 'The LORD our God, the LORD is one') demands exclusive devotion. Christ who is himself the Lord calls disciples to the absolute monotheism of kingdom-loyalty.</p>",
"14": "<p>'The Pharisees, who were lovers of money, heard all these things, and they ridiculed him' — the Pharisees' love of money (philargyroi — lovers of money/silver) and their ridicule (exemyktērizon — turned up their noses, sneered) is the response of those who have divided their service between God and money and resent the exposure. Their religiosity and their financial ambition coexist — a coexistence Christ's teaching makes impossible. The Pharisees who 'justify themselves before men' (v.15) use religious performance to maintain social standing while practicing the divided service Christ has just condemned.</p>",
"15": "<p>'And he said to them, You are those who justify yourselves before men, but God knows your hearts. For what is exalted among men is an abomination before God' — the divine heart-knowledge (God knows your hearts — kardiognōstēs, used of God in Acts 1:24 and 15:8) cuts through the social performance of righteousness. The Pharisees are justified before men (their social reputation is excellent) but their hearts are known to God. The 'abomination' (bdelygma — the strongest word of divine rejection in the LXX, used for idols) of human social-status-seeking before God reveals that self-justification is a form of idolatry: making oneself the god of one's social world.</p>",
"16": "<p>'The Law and the Prophets were until John; since then the good news of the kingdom of God is preached, and everyone forces his way into it' — the historical turning-point: John marks the end of the Law-and-Prophets era; Christ inaugurates the kingdom-proclamation era. The 'forcing one's way in' (biazetai — either 'the kingdom presses forward forcefully' or 'everyone presses forcefully into it') suggests the urgent, overwhelming energy of the kingdom's arrival. Christ himself is the one 'who is to come' (7:19-20) at whose arrival the old order transitions to the new.</p>",
"17": "<p>'But it is easier for heaven and earth to pass away than for one dot of the Law to become void' — the continuity of the Law within the new kingdom-era: Christ fulfills rather than abolishes (Matt 5:17). The Law's requirements are not reduced in the kingdom; they are fulfilled in Christ (Rom 8:4 — 'the righteous requirement of the law might be fulfilled in us, who walk not according to the flesh but according to the Spirit'). The 'dot' (keraia — the smallest stroke of a Hebrew letter) is secured in Christ's perfect obedience and atonement.</p>",
"18": "<p>'Everyone who divorces his wife and marries another commits adultery, and he who marries a woman divorced from her husband commits adultery' — the divorce saying in this context addresses the Pharisees' use of legal loopholes to circumvent the covenant-faithfulness the Law requires. Christ restores the original creation-intent of marriage (Gen 2:24 — 'one flesh'). He who is himself the faithful bridegroom (Eph 5:25-32 — 'as Christ loved the church and gave himself for her') defines the standard of covenant fidelity. His own faithfulness to his people unto death is the model for human covenant fidelity.</p>",
"19": "<p>'There was a rich man who was clothed in purple and fine linen and who feasted sumptuously every day' — the rich man's clothing (purple — the most expensive dye; fine linen — priestly/royal cloth) and daily feasting marks him as among the wealthiest of the wealthy. He is not described as evil or wicked — only as wealthy and oblivious. His sin is not active cruelty but radical disconnection from the suffering at his gate. Christ who 'had no place to lay his head' (9:58) and whose mother offered the poverty offering (2:24) stands as the implicit contrast: the one who became poor so that we might become rich (2 Cor 8:9).</p>",
"20": "<p>'And at his gate was laid a poor man named Lazarus, covered with sores' — Lazarus (the only named character in any of Jesus's parables — a detail that has been much discussed) bears a name meaning 'God has helped' or 'God will help.' His condition (covered with sores, at the gate, longing for crumbs) is the maximum degradation of the poor. He lies at the gate — on the threshold of the rich man's abundance — and receives nothing. The gate that separates them in life becomes the 'great chasm' (v.26) that separates them in death. Christ crosses every such gate and chasm: he goes to Lazarus-the-poor (Luke 4:18; 7:22) and raises Lazarus-the-dead (John 11).</p>",
"21": "<p>'Who desired to be fed with what fell from the rich man's table. Moreover, even the dogs came and licked his sores' — Lazarus's passive reception (dogs lick his sores — an act of kindness from animals that he could not resist or welcome) is the depth of his helplessness. The 'crumbs from the table' language echoes the Syrophoenician woman's faith-request (Matt 15:27 — 'even the dogs eat the crumbs that fall from their master's table'). But Lazarus receives not even crumbs. The rich man is the 'table' that should be feeding others; he withholds what Lazarus needs. Christ is the table that never withholds (John 6:35 — 'I am the bread of life; whoever comes to me shall not hunger').</p>",
"22": "<p>'The poor man died and was carried by the angels to Abraham's side. The rich man also died and was buried' — the two deaths and their contrasts: Lazarus is 'carried by angels' to Abraham; the rich man 'was buried' with the ceremony his wealth demands. In death, the reversal begins: the one with no burial worth noting is transported by angels; the one with a proper burial goes to Hades. The angels who serve Christ (22:43 — 'an angel from heaven appeared to him, strengthening him') also serve the Lazaruses of the world. Christ himself was buried — like the rich man — but rose, unlike either.</p>",
"23": "<p>'And in Hades, being in torment, he lifted up his eyes and saw Abraham far off and Lazarus at his side' — the rich man's lifting of his eyes in Hades to see Abraham and Lazarus 'far off' reverses the life-situation: in life, Lazarus was at the gate (near but not received); in death, the rich man is far from Abraham (distant from the covenant). The covenant promise (to be with Abraham) is fulfilled in Lazarus; the covenant failure (of ignoring the needy at one's gate) is exposed in the rich man. Christ who is himself 'Abraham's son' (in the sense of the covenant's fulfillment) grants Abraham's bosom to those who receive his kingdom.</p>",
"24": "<p>'Father Abraham, have mercy on me, and send Lazarus to dip the end of his finger in water and cool my tongue, for I am in anguish in this flame' — the rich man still addresses Lazarus as an errand-runner ('send Lazarus') — the same posture as in life, where he would have directed servants to bring him things. He has not understood even in death that Lazarus is his equal or superior. His request for a drop of water echoes Lazarus's longing for crumbs — both longing for what is denied. The one who denied crumbs now asks for drops; the economy of mercy he refused operates against him.</p>",
"25": "<p>'Child, remember that you in your lifetime received your good things, and Lazarus in like manner bad things; but now he is comforted here, and you are in anguish' — Abraham's address 'child' (teknon) to the rich man maintains familial relationship even in judgment — he is addressed with the same warmth as the father's address to the elder son (15:31). But the reversal is irrevocable: good-things-in-life → anguish-in-death; bad-things-in-life → comfort-in-death. The Magnificat (1:52-53) has reached its eschatological fulfillment: 'he has filled the hungry with good things, and the rich he has sent away empty.'</p>",
"26": "<p>'And besides all this, between us and you a great chasm has been fixed, in order that those who would pass from here to you may not be able, and none may cross from there to us' — the great chasm (chasma mega) is the irreversibility of the post-death state. The parable does not teach annihilation or purgatory but the permanent fixing of the eternal state after death. The cross is the place where Christ bridges the chasm — not between hell and heaven but between the Father's presence and the far country of sin. He who descended into the far country (Incarnation) and into the depths (death) and rose again bridges the only chasm that grace can cross.</p>",
"27": "<p>'Then I beg you, father, to send him to my father's house — for I have five brothers — so that he may warn them, lest they also come into this place of torment' — the rich man's concern for his five brothers reveals that his conscience knows what they need: warning, repentance. The irony is that the warning they need is available: 'they have Moses and the Prophets' (v.29). The five brothers already have the Scriptures that point to Christ. The problem is not lack of information but the will to receive it. The rich man who ignored Scripture in life asks for a resurrection-miracle for his brothers — but Abraham's response points back to the same Scripture.</p>",
"28": "<p>'I have five brothers, so that he may warn them, lest they also come into this place of torment' — the concern for the five brothers (five = the complete number of siblings in the family) is the only act of love the rich man performs in the parable. But it is too late for him and unnecessary for them: they have what is needed. The parable implicitly indicts the assumption that miraculous signs would produce faith. Christ himself will raise Lazarus (John 11) and many 'will not believe' (John 11:45-48 — the chief priests plan to kill both Jesus and Lazarus). Signs do not produce faith where the heart is hardened.</p>",
"29": "<p>'But Abraham said, They have Moses and the Prophets; let them hear them' — Moses and the Prophets (the Law and the Prophets) are sufficient witnesses to the truth about wealth, poverty, judgment, and the coming Messiah. Christ says elsewhere that the Scriptures 'bear witness about me' (John 5:39-40). The five brothers who have Moses and the Prophets have the witness of Christ in the OT's testimony. The rich man's request for a resurrection-visitor is the request for extraordinary evidence when ordinary evidence (Scripture) is refused. 'If they do not hear Moses and the Prophets, neither will they be convinced if someone rises from the dead' (v.31).</p>",
"30": "<p>'No, father Abraham, but if someone goes to them from the dead, they will repent' — the rich man's insistence that a resurrection would produce repentance is the assumption that extraordinary evidence overcomes resistance. The assumption is refuted by history: Christ rose from the dead, and the same chief priests who knew about the resurrection (Matt 28:11-15 — they bribed the guards to spread a false story) did not repent. The resurrection was and is the decisive evidence; those who refuse it do not lack evidence but willingness. 'He has risen from the dead' (Matt 28:7) is available to all; repentance requires not more evidence but a new heart.</p>",
"31": "<p>'He said to him, If they do not hear Moses and the Prophets, neither will they be convinced if someone rises from the dead' — the final word of the parable is the word Christ speaks to his own resurrection's reception: the Scriptures are sufficient witness; those who refuse them will not be persuaded by the resurrection either. This was demonstrated in Jerusalem: 'many of the Jews who had come to Mary and had seen what he did believed in him, but some of them went to the Pharisees' (John 11:45-46). The resurrection of Lazarus produced both faith and intensified opposition. The resurrection of Christ did the same. The heart that refuses Moses will refuse the risen Christ.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, LUKE_CH14_16)
    save_comm('mkt-christ', 'luke', existing)
    ch14 = len(existing.get('14', {}))
    ch15 = len(existing.get('15', {}))
    ch16 = len(existing.get('16', {}))
    print(f'Luke 14: {ch14}/35. Luke 15: {ch15}/32. Luke 16: {ch16}/31.')

if __name__ == '__main__':
    main()
